INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2190, 202396, 6, 694, '我为自己骄傲', '今天我终于下定决心离开他，一滴泪也没有掉……曾经我以为我会爱他很久很久，也曾天真的以为我对他好，他也会对我好！可是直到现在我才发现我错了，错得离谱……他太自以为是了，什么都以自己为中心，从不过问我的感受，什么都要依着他顺着他，我只是他的陪衬品，可是我要的不是这种生活啊！找男朋友是为了有人疼，没想到却找了个要自己去疼的人，他，像个孩子，一直是个孩子，不懂事又任性的孩子……
<br>
<br>我没哭，一滴泪也没有掉，我为自己骄傲，我终于也可以这么坚强的面对这段错误的感情……我终于有勇气离开他……
<br>
<br>不要再说了，不想再听到他说，他爱我，他是那么的珍惜我，如果真的爱我不该这么对我的啊！如果可以笨到底，但到底还是我，谁能待我好待我差太清楚，想继续装傻，却有无力受折磨，心里羡慕有些人盲目到不计后果……', '今天我终于下定决心离开他，一滴泪也没有掉……曾经我以为我会爱他很久很久，也曾天真的以为我对他好，他也会对我好！可是直到现在我才发现我错了，错得离谱……他太自以为是了，什么都以自己为中心，从不过问我的感受，什么都要依着他顺着他，我只是他的陪衬品，可是我要的不是这种生活啊！找男朋友是为了有人疼，没想到却找了个要自己去疼的人，他，像个孩子，一直是个孩子，不懂事又任性的孩子……

我没哭，一滴泪也没有掉，我为自己骄傲，我终于也可以这么坚强的面对这段错误的感情……我终于有勇气离开他……

不要再说了，不想再听到他说，他爱我，他是那么的珍惜我，如果真的爱我不该这么对我的啊！如果可以笨到底，但到底还是我，谁能待我好待我差太清楚，想继续装傻，却有无力受折磨，心里羡慕有些人盲目到不计后果……', NULL, '2003-05-12 13:24:00', 12, '20031020174526_bbsid_202396_board_6_71e32331ed.html', '20031020174526');
